  ('elementary-0c700c30-moex-00638', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '甲民族數千年居住於某地區，目前為乙民族國家的一個自治區，藉由其傳統統治機制行使自治，甲希望 依民族自決原則獨立為一國。甲欲成立國家尚缺下列那一項國家成立要件？', '["領土", "政府", "人民", "主權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00639', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '下列關於國家、統治者與人民關係的說法，何者最符合當今對民主政治的想像？', '["元首為國家主權之象徵，行使所有統治權力", "人民為國家構成要件之一，須服從國家之各種規範", "國家主權應為人民所掌有，一國元首須由人民選舉產生", "國家應是實現人民權益保障的機制，而非人民之支配者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00640', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '假設某一封閉的市場經濟體系只生產手機與腳踏車兩種商品且機會成本遞增。考慮兩種商品之生產可能 選擇，如果人們變得熱愛騎腳踏車，則與原生產點比較起來，新的生產點其：', '["生產手機與腳踏車的機會成本都會增加", "生產手機與腳踏車的機會成本都會減少", "生產手機的機會成本會增加，且生產腳踏車的機會成本會減少", "生產手機的機會成本會減少，且生產腳踏車的機會成本會增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00641', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '2019年政府修法通過道路交通管理處罰條例第73條規定「電動自行車駕駛人未依規定戴安全帽者，處駕 駛人新臺幣3百元罰鍰。｣，倘若此法的修正通過使安全帽市場的交易量增加與均衡價格上漲，下列何者 最能說明安全帽市場變動的情況？', '["市場需求線向右移動", "市場需求線向左移動", "市場供給線向右移動", "市場供給線向左移動"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00642', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '有關國際貿易的思維，下列那一選項是正確的推論順序？', '["比較利益→生產機會成本的差異→國際貿易", "國際貿易→比較利益→生產機會成本的差異", "生產機會成本的差異→比較利益→國際貿易", "比較利益→國際貿易→生產機會成本的差異"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00643', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '由於受到新冠肺炎疫情的影響，美國採取寬鬆貨幣政策來拯救經濟，加上面臨財政赤字，美元大幅貶值。 關於美元貶值對臺灣影響之敘述，下列何者正確？', '["出口商品價格變得更便宜，故對臺灣出口業者較有利", "美國出口臺灣的商品變便宜，故對臺灣進口業與消費者有利", "臺灣出口業者因美元貶值，收到的貨款將可換到更多新臺幣", "美國出口臺灣的商品變貴，故對美國出口業不利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00644', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '臺灣進入高齡化社會，近年來自東南亞伊斯蘭信仰的女性看護移工快速增加，但國人對伊斯蘭信仰卻鮮 少認識，引發不少誤會甚至歧視的事件。下列何種做法無助於解決上述的情況？', '["學校鼓勵學生選修認識多元文化與宗教的課程", "電視臺製作並播出與東南亞文化與信仰相關的節目", "地方政府定期舉辦東南亞文化慶典活動", "為看護移工辦理免費中文課程並鼓勵參加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00645', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '近年來若干縣市政府為了便民紛紛建置共享單車系統，若某共享單車系統收費標準為租用時間在 4 小時 以內，每30分鐘收費10元。則該系統較屬於那種財貨？', '["具可排他性與獨享性", "具可排他性與共享性", "具不可排他性與獨享性", "具不可排他性與共享性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
